                            "code": "# === ENTRY-LEVEL EXAMPLE ===\n# TASK      - Basic usage of rich.print(), Console, Table, Progress — understand the core syntax and behavior.\n# APPROACH  - Simple example with minimal parameters; no edge cases.\n# STRENGTHS - Clear, readable; shows the fundamental pattern.\n# WEAKNESSES- Not production-ready; no error handling or complex scenarios.\nfrom rich.console import Console\nfrom rich.table import Table\nfrom rich.progress import track\nimport time\nconsole = Console()\nconsole.print(\"[bold cyan]Welcome[/bold cyan]\")\nt = Table(title=\"Users\")\nt.add_column(\"name\", style=\"cyan\")\nt.add_column(\"age\",  style=\"magenta\", justify=\"right\")\nt.add_row(\"Alice\", \"30\")\nt.add_row(\"Bob\", \"25\")\nconsole.print(t)\nfor _ in track(range(20), description=\"loading\"):\n    time.sleep(0.05)"
